            author: msg.sender,
            content: content,
            totalPower: 0
        });
        emit PostCreated(postCount, msg.sender, content);
        return postCount;
    }

    function getPost(uint256 postId) public view returns (address author, string memory content, uint256 totalPower) {
        Post memory post = posts[postId];
        require(post.author != address(0), "Post does not exist");
        return (post.author, post.content, post.totalPower);
    }

    function boostPost(uint256 postId) public payable {
        require(postId <= postCount, "Post does not exist");
        require(msg.value > 0, "Value must be greater than 0");
        require(posts[postId].author != msg.sender, "Author cannot boost their own post");

        Post storage post = posts[postId];
        post.totalPower += msg.value;
        authorBalances[post.author] += msg.value;
        emit PostBoosted(postId, msg.value);
    }

    function authorBalancesOf(address author) public view returns (uint256) {
        return authorBalances[author];
    }

